 import { sanitizeUrl } from "../data/url";

+// Strictly parse and reconstruct HTML to prevent injection attacks
+const sanitizeSrcdoc = (html: string): string => {
+  const parser = new DOMParser();
+  const doc = parser.parseFromString(html, "text/html");
+  
+  // Remove potentially dangerous elements
+  const dangerousElements = doc.querySelectorAll("script, iframe, object, embed");
+  dangerousElements.forEach(el => el.remove());
+  
+  // Remove event handlers and javascript URLs from attributes
+  const allElements = doc.getElementsByTagName("*");
+  for (let i = 0; i < allElements.length; i++) {
+    const el = allElements[i];
+    for (const attr of Array.from(el.attributes)) {
+      const name = attr.name.toLowerCase();
+      const value = attr.value.toLowerCase();
+      if (name.startsWith("on") || value.startsWith("javascript:")) {
+        el.removeAttribute(attr.name);
+      }
+    }
+  }
+  
+  return doc.documentElement.outerHTML;
+};
+
+// Determine if same-origin sandbox is required for specific trusted providers
+const requiresSameOrigin = (url: string): boolean => {
+  const trustedHosts = ["youtube.com", "youtu.be", "vimeo.com", "open.spotify.com"];
+  try {
+    const urlObj = new URL(url);
+    return trustedHosts.some(host => urlObj.hostname.endsWith(host));
+  } catch {
+    return false;
+  }
+};
